import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { careerAPI, aiAPI } from '../services/api';
import {
  ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Cell
} from 'recharts';
import { Brain, DollarSign, Sparkles } from 'lucide-react';
import VoiceAdvisor from '../components/shared/VoiceAdvisor';

const COLORS = ['#6366f1', '#a855f7', '#06b6d4'];

export default function ResultsPage() {
  const { user } = useAuth();
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const runPrediction = async () => {
    setLoading(true);
    setError('');

    try {
      const quizScores = JSON.parse(localStorage.getItem('quiz_scores') || '{}');

      const payload = {
        skills: user?.skills || [],
        interests: user?.interests || [],
        education_level: user?.education_level || "Bachelor's Degree",
        gpa: parseFloat(user?.gpa) || 3.0,
        personality_type: user?.personality_type || 'Analytical',
        experience_years: parseInt(user?.experience_years) || 0,
        quiz_scores: quizScores,
      };

      const res1 = await careerAPI.predict(payload);

      let aiData = null;
      try {
        const res2 = await aiAPI.recommend(payload);
        // The new ollama API returns { recommendations: { ... } }
        aiData = res2.data.recommendations || res2.data.result || res2.data;
      } catch (err) {
        console.error("AI recommendation failed", err);
        aiData = { raw: "⚠️ AI insights unavailable. Showing ML predictions only." };
      }

      setResults({
        traditional: res1.data.recommendations,
        ai: aiData
      });

    } catch (e) {
      setError('Prediction failed. Ensure you have completed the assessment.');
    } finally {
      setLoading(false);
    }
  };

  const barData = results?.traditional?.map((r) => ({
    name: r.career_name?.split(' ').slice(0, 2).join(' '),
    match: r.match_percentage,
  })) || [];

  return (
    <div className="min-h-screen bg-gradient-to-br from-[#020617] via-[#020617] to-[#0f172a] text-white p-6">

      {/* HEADER */}
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-3xl font-bold flex items-center gap-3">
          <Brain className="text-indigo-400" />
          Career AI Dashboard
        </h1>

        <button
          onClick={runPrediction}
          disabled={loading}
          className="px-6 py-2.5 rounded-xl bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500 font-semibold shadow-lg hover:scale-105 transition"
        >
          {loading ? "Analyzing..." : "✨ Get AI Insights"}
        </button>
      </div>

      {error && <div className="text-red-400 mb-4">{error}</div>}

      {loading && (
        <div className="flex flex-col items-center justify-center py-20 text-white/70 space-y-4">
          <div className="w-16 h-16 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin shadow-[0_0_15px_rgba(99,102,241,0.5)]"></div>
          <p className="animate-pulse text-lg tracking-wide text-indigo-200">Analyzing your profile & synthesizing AI insights...</p>
        </div>
      )}

      {!results && !loading && (
        <div className="text-center py-20 text-indigo-200/50 flex flex-col items-center">
          <Sparkles size={48} className="mb-4 text-indigo-400/30" />
          <p className="text-xl font-light tracking-wider">Click below to generate your personalized career plan</p>
          <button
            onClick={runPrediction}
            className="mt-8 px-8 py-3 rounded-full bg-white/5 border border-white/10 hover:bg-white/10 hover:scale-105 transition-all text-white backdrop-blur-md shadow-[0_0_20px_rgba(99,102,241,0.2)]"
          >
            Generate Now
          </button>
        </div>
      )}

      {results && results.traditional && !loading && (
        <>
          {/* TOP CARDS */}
          <div className="grid md:grid-cols-3 gap-6 mb-10">
            {results.traditional.map((r, i) => (
              <div
                key={i}
                className={`p-6 rounded-2xl backdrop-blur-xl border border-white/10 shadow-xl transition hover:scale-[1.03]
                ${i === 0 ? 'bg-indigo-500/10 border-indigo-400/30' : 'bg-white/5'}`}
              >
                {i === 0 && (
                  <span className="text-xs bg-indigo-500/30 px-2 py-1 rounded-full">
                    ⭐ Best Match
                  </span>
                )}

                <h3 className="text-lg font-bold mt-2">{r.career_name}</h3>

                <p className="text-indigo-400 mt-2 font-semibold">
                  {r.match_percentage}% Match
                </p>

                <p className="text-green-400 flex items-center gap-1 text-sm mt-1">
                  <DollarSign size={14} /> ${(r.avg_salary / 1000).toFixed(0)}K
                </p>

                <Link
                  to={`/roadmap/${encodeURIComponent(r.career_name)}`}
                  className="block mt-4 text-sm text-purple-400 hover:underline"
                >
                  View Roadmap →
                </Link>
              </div>
            ))}
          </div>

          {/* CHART */}
          <div className="mb-10 p-6 rounded-2xl bg-white/5 border border-white/10 backdrop-blur-xl">
            <h3 className="mb-4 font-semibold text-lg">📊 Match Comparison</h3>

            <ResponsiveContainer width="100%" height={250}>
              <BarChart data={barData}>
                <XAxis dataKey="name" stroke="#aaa" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="match" radius={[6, 6, 0, 0]}>
                  {barData.map((_, i) => (
                    <Cell key={i} fill={COLORS[i]} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* SKILLS */}
          <div className="mb-10 p-6 rounded-2xl bg-white/5 border border-white/10 backdrop-blur-xl">
            <h3 className="mb-4 font-semibold text-lg">🧠 Required Skills</h3>

            <div className="flex flex-wrap gap-2">
              {(results.traditional[0]?.required_skills || []).map(skill => (
                <span
                  key={skill}
                  className="px-3 py-1.5 rounded-lg bg-indigo-500/20 text-indigo-300 text-sm"
                >
                  {skill}
                </span>
              ))}
            </div>
          </div>

          {/* AI SECTION (GLASSMORPHISM) */}
          {results.ai && (
            <div className="mb-10 p-8 rounded-3xl bg-gradient-to-br from-indigo-500/10 via-purple-500/5 to-pink-500/10 border border-white/10 backdrop-blur-2xl shadow-[0_8px_32px_rgba(0,0,0,0.3)] relative overflow-hidden group hover:border-white/20 transition-all duration-500">
              <div className="absolute top-0 right-0 w-64 h-64 bg-purple-500/20 rounded-full blur-[80px] -z-10 group-hover:bg-purple-500/30 transition-all"></div>
              <h2 className="text-2xl font-bold mb-6 flex items-center gap-3 tracking-wide">
                <Sparkles className="text-purple-400 animate-pulse" />
                AI Career Advisor Insights
              </h2>

              {results.ai.raw ? (
                <p className="text-white/70 italic p-4 bg-white/5 rounded-xl border border-white/10">{results.ai.raw}</p>
              ) : (
                <div className="grid md:grid-cols-2 gap-8">
                  <div className="p-6 rounded-2xl bg-white/[0.03] border border-white/[0.05] hover:bg-white/[0.05] transition">
                    <h4 className="text-blue-400 font-semibold mb-3 flex items-center gap-2"><Brain size={16}/> Recommended Streams</h4>
                    <ul className="space-y-2">
                      {(results.ai.streams || []).map((s, i) => <li key={i} className="flex items-center gap-2 text-sm text-white/80"><div className="w-1.5 h-1.5 rounded-full bg-blue-400"></div>{s}</li>)}
                    </ul>
                  </div>

                  <div className="p-6 rounded-2xl bg-white/[0.03] border border-white/[0.05] hover:bg-white/[0.05] transition">
                    <h4 className="text-purple-400 font-semibold mb-3">🎓 Relevant Courses</h4>
                    <ul className="space-y-2">
                      {(results.ai.courses || []).map((c, i) => <li key={i} className="flex items-start gap-2 text-sm text-white/80"><div className="mt-1.5 w-1.5 h-1.5 rounded-full bg-purple-400 shrink-0"></div><span>{c}</span></li>)}
                    </ul>
                  </div>

                  <div className="md:col-span-2 p-6 rounded-2xl bg-white/[0.03] border border-white/[0.05] hover:bg-white/[0.05] transition">
                    <h4 className="text-green-400 font-semibold mb-2">💡 Why This Fits You</h4>
                    <p className="text-sm/relaxed text-white/80 mt-1">{results.ai.reason}</p>
                  </div>

                  <div className="p-6 rounded-2xl bg-white/[0.03] border border-white/[0.05] hover:bg-white/[0.05] transition">
                    <h4 className="text-yellow-400 font-semibold mb-3">⚡ Skills to Develop</h4>
                    <div className="flex flex-wrap gap-2 mt-2">
                      {(results.ai.skills || []).map((s, i) => (
                        <span key={i} className="px-3 py-1.5 bg-yellow-500/10 border border-yellow-500/20 text-yellow-200 rounded-lg text-xs shadow-sm shadow-yellow-500/5">
                          {s}
                        </span>
                      ))}
                    </div>
                  </div>

                  <div className="p-6 rounded-2xl bg-white/[0.03] border border-white/[0.05] hover:bg-white/[0.05] transition">
                    <h4 className="text-cyan-400 font-semibold mb-3">🗺️ Roadmap Preview</h4>
                    <ol className="relative border-l border-cyan-500/30 ml-3 space-y-4">
                      {(results.ai.roadmap || []).map((step, i) => (
                        <li key={i} className="ml-4">
                          <div className="absolute w-2 h-2 bg-cyan-400 rounded-full -left-1.5 border border-[#0f172a]"></div>
                          <p className="text-sm font-medium text-white/90">{step.title || step}</p>
                        </li>
                      ))}
                    </ol>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* VOICE AI */}
          <VoiceAdvisor />
        </>
      )}
    </div>
  );
}
